#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
  float weight;
  long assign;
  float cost;
} Point_Struct;

// Kernel to compute distances and update work_mem for pgain
__kernel void pgain_kernel(
    __global const Point_Struct* p,
    __global const float* coord,
    __global float* work_mem,
    __global const int* center_table,
    __global char* switch_membership,
    int num,
    int dim,
    long x,
    int K)
{
  int i = get_global_id(0);
  if (i >= num) return;

  // Compute distance from point i to point x
  float x_cost = 0.0f;
  for (int d = 0; d < dim; d++) {
    float diff = coord[i * dim + d] - coord[x * dim + d];
    x_cost += diff * diff;
  }
  x_cost *= p[i].weight;

  float current_cost = p[i].cost;

  if (x_cost < current_cost) {
    switch_membership[i] = 1;
    work_mem[i * (K + 1) + K] += x_cost - current_cost;
  } else {
    int assign = p[i].assign;
    int ct = center_table[assign];
    if (ct >= 0 && ct < K) {
      work_mem[i * (K + 1) + ct] += current_cost - x_cost;
    }
  }
}

// Kernel to initialize point costs based on distance to center 0
__kernel void init_costs_kernel(
    __global Point_Struct* p,
    __global const float* coord,
    int num,
    int dim)
{
  int i = get_global_id(0);
  if (i >= num) return;

  float distance = 0.0f;
  for (int d = 0; d < dim; d++) {
    float diff = coord[i * dim + d] - coord[0 * dim + d];
    distance += diff * diff;
  }
  p[i].cost = distance * p[i].weight;
  p[i].assign = 0;
}

// Kernel to update costs when opening a new center
__kernel void update_costs_kernel(
    __global Point_Struct* p,
    __global const float* coord,
    __global char* switch_membership,
    int num,
    int dim,
    long new_center)
{
  int i = get_global_id(0);
  if (i >= num) return;

  float distance = 0.0f;
  for (int d = 0; d < dim; d++) {
    float diff = coord[i * dim + d] - coord[new_center * dim + d];
    distance += diff * diff;
  }
  float new_cost = distance * p[i].weight;

  if (new_cost < p[i].cost) {
    p[i].cost = new_cost;
    p[i].assign = new_center;
  }
}

// Kernel to compute total cost for a partition
__kernel void compute_partition_cost_kernel(
    __global const Point_Struct* p,
    __global float* costs,
    int start,
    int end,
    int pid)
{
  float mytotal = 0.0f;
  for (int k = start; k < end; k++) {
    mytotal += p[k].cost;
  }
  costs[pid] = mytotal;
}

// Kernel to accumulate center coordinates (contcenters)
__kernel void contcenters_kernel(
    __global Point_Struct* p,
    __global float* coord,
    __global float* new_coord,
    __global float* new_weight,
    int num,
    int dim)
{
  int i = get_global_id(0);
  if (i >= num) return;

  if (p[i].assign != i) {
    int assign = p[i].assign;
    float relweight = p[i].weight / (p[assign].weight + p[i].weight);

    for (int d = 0; d < dim; d++) {
      new_coord[assign * dim + d] = coord[assign * dim + d] * (1.0f - relweight) + coord[i * dim + d] * relweight;
    }
    new_weight[assign] += p[i].weight;
  }
}

// Kernel to copy center data
__kernel void copycenters_kernel(
    __global const Point_Struct* src_p,
    __global const float* src_coord,
    __global Point_Struct* dest_p,
    __global float* dest_coord,
    __global long* centerIDs,
    __global const char* is_a_median,
    long offset,
    int num,
    int dim,
    int* k_ptr)
{
  int i = get_global_id(0);
  if (i >= num) return;

  if (is_a_median[i]) {
    int k = *k_ptr;
    dest_p[k].weight = src_p[i].weight;
    dest_p[k].assign = src_p[i].assign;
    dest_p[k].cost = src_p[i].cost;

    for (int d = 0; d < dim; d++) {
      dest_coord[k * dim + d] = src_coord[i * dim + d];
    }
    centerIDs[k] = i + offset;
    *k_ptr = k + 1;
  }
}

// Kernel to compute hiz (initial upper bound)
__kernel void compute_hiz_kernel(
    __global const Point_Struct* p,
    __global const float* coord,
    __global float* hizs,
    int start,
    int end,
    int dim,
    int pid)
{
  float myhiz = 0.0f;
  for (int kk = start; kk < end; kk++) {
    float distance = 0.0f;
    for (int d = 0; d < dim; d++) {
      float diff = coord[kk * dim + d] - coord[0 * dim + d];
      distance += diff * diff;
    }
    myhiz += distance * p[kk].weight;
  }
  hizs[pid] = myhiz;
}

// Kernel to set is_center flags
__kernel void set_is_center_kernel(
    __global const Point_Struct* p,
    __global char* is_center,
    int num)
{
  int i = get_global_id(0);
  if (i >= num) return;

  is_center[p[i].assign] = 1;
}

// Kernel to check and update center status
__kernel void update_center_status_kernel(
    __global char* is_center,
    __global const float* gl_lower,
    __global const int* center_table,
    int num)
{
  int i = get_global_id(0);
  if (i >= num) return;

  if (is_center[i] && gl_lower[center_table[i]] > 0) {
    is_center[i] = 0;
  }
}

// Kernel to update point assignments after gain check
__kernel void update_assignments_kernel(
    __global Point_Struct* p,
    __global const float* coord,
    __global const char* switch_membership,
    __global const float* gl_lower,
    __global const int* center_table,
    int num,
    int dim,
    long x)
{
  int i = get_global_id(0);
  if (i >= num) return;

  int assign = p[i].assign;
  bool close_center = gl_lower[center_table[assign]] > 0;

  if (switch_membership[i] == 1 || close_center) {
    float distance = 0.0f;
    for (int d = 0; d < dim; d++) {
      float diff = coord[i * dim + d] - coord[x * dim + d];
      distance += diff * diff;
    }
    p[i].cost = distance * p[i].weight;
    p[i].assign = x;
  }
}
